head.script:
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vCoCd = scwin.login.coCd;
scwin.vCoClsCd = scwin.login.coClsCd;
scwin.isSubCompany = false;
scwin.isFirst = true;
scwin.txtCoClsCd;
scwin.txtCoCd;
scwin.hid_srchAcctDeptCd;


var KOREA_WON = ACConstants.KOREA_WON; 		//원화코드
var isInPost = false;		//TR 컴포넌트가 데이터를 Post 중인지 여부
scwin.parent_fixedAsetNo;

scwin.onpageload = function () {
    scwin.parent_fixedAsetNo = $c.data.getParameter("fixedAsetNo")

    let codeOptions = [
        { grpCd: "FI028", compID: "acb_acqCls" },
        { grpCd: "ZZ006", compID: "acb_crcCd" }

    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = async function () {

    $c.gus.cfTurnCreateFlag(true);
    // $c.gus.cfDisableKey();
    $c.gus.cfDisableObjects([tbl_search2]);

    // scwin.f_SearchHeaderCreate();				//조회조건 데이터셋 생성
    //cfDisableObjects(tbl_aset);			//자산입력 disable
    scwin.f_AsetOnOff(false);					//자산입력 disable
    scwin.f_AreaMgntOnOff(false);
    // $c.gus.cfDisableBtn([bUpdate, bSave]);

    $c.gus.cfDisableObjects([ed_srchFixedAsetNo, acb_srchDeprCd, acb_srchAsetPatternCd, ed_srchOrgFixedAsetNo, chk_IncluYn, ed_lsClntNo, ed_lsClntNm, acb_acqCls, ed_acqClsStdt, ed_acqClsEnddt]);

    //자산유형 조회
    $c.sbm.execute(sbm_asetPattern);

    scwin.f_FieldClear();

    // gr_master.TitleHeight = "30";

    scwin.f_setCompanyInfo();

    // 팝업으로 열린 경우 자산번호 세팅

}

scwin.ondataload = function () {

    if (scwin.parent_fixedAsetNo != null) {
        ed_srchFixedAsetNo.setValue(scwin.parent_fixedAsetNo);

        $p.setTimeout(function () {

            scwin.f_Retrieve();

        }, { "delay": 150 });


    }
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, [ed_acqDtStDt, ed_acqDtEndDt]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
    ed_acqDtStDt.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6) + "01");
    ed_acqDtEndDt.setValue(WebSquare.date.getCurrentServerDate());
    ed_srchAcctDeptCd.setValue("00000");
    // ed_srchAcctDeptNm.setValue("전사");
    ed_acqDtStDt.focus();
    chk_IncluYn.checkAll(true);
    acb_asetPatternCd.setValue("05");
}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function (e) {

    // 사용자 구분이 자회사('SA')인 경우 
    if (scwin.vUserHomeClsCd == ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.isSubCompany = true;
    } else {
        // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        scwin.vCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    scwin.txtCoCd = scwin.vCoCd;
    scwin.txtCoClsCd = scwin.vCoClsCd;

    scwin.f_srchDeptPopUp('T'); // 조회조건  '귀속부서' 팝업
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await scwin.f_RetrieveValidate()) {
        return false;
    }

    if (chk_IncluYn.getValue() == "1") {
        dma_search.set("retrieveClsCd", "1");
    } else {
        dma_search.set("retrieveClsCd", "");
    }

    dma_search.set("asetPatternCd", acb_srchAsetPatternCd.getValue());
    // dma_search.set("acctDeptCd", scwin.hid_srchAcctDeptCd);
    dma_search.set("fixedAsetNo", ed_srchFixedAsetNo.getValue());
    dma_search.set("orgFixedAsetNo", ed_srchOrgFixedAsetNo.getValue());
    dma_search.set("coCd", scwin.txtCoCd);
    dma_search.set("coClsCd", scwin.txtCoClsCd);

    await $c.sbm.execute(sbm_search);
}

//-------------------------------------------------------------------------
// 조회 검증
//-------------------------------------------------------------------------
scwin.f_RetrieveValidate = async function () {
    if (!await $c.gus.cfValidate([ed_srchAcctDeptCd])) {
        return;
    }

    if (ds_asetList.getModifiedIndex().length > 0) {
        if (await $c.win.confirm(MSG_CM_CRM_005 + "1") == false)
            return false;
    }

    if (ds_landinfo.getTotalRow() > 0 && ds_landinfo.getModifiedIndex().length > 0) {
        if (await $c.win.confirm(MSG_CM_CRM_005 + "2") == false)
            return false;
    }

    if (!await $c.gus.cfValidate([tbl_search])) {
        return false;
    }

    //취득 일자 체크
    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg("취득일자는 필수입력 항목입니다.");
        ed_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg("취득일자는 필수입력 항목입니다.");
        ed_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        // if (!$c.gus.cfValidateValue(ed_acqDtEndDt.getValue(),"minDate=" + ed_acqDtStDt.getValue())) {
        if (WebSquare.date.dateDiff(ed_acqDtStDt.getValue(), ed_acqDtEndDt.getValue()) < 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ed_acqDtStDt.focus();
            return false;
        }
    }

    return true;
}

