//-------------------------------------------------------------------------
// 입력 Validation
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {
    if (await scwin.f_ValidateAset() == false)
        return false;

    if (await scwin.f_ValidateAreaMgnt() == false)
        return false;

    return true;
}

//-------------------------------------------------------------------------
// 자산입력 Validation
//-------------------------------------------------------------------------
scwin.f_ValidateAset = async function () {
    if (!await $c.gus.cfValidate([ed_fixedAsetNm])) {
        return false;
    }
    return true;
}

//-------------------------------------------------------------------------
// 면적관리 입력 Validation
//-------------------------------------------------------------------------
scwin.f_ValidateAreaMgnt = async function () {
    //면적관리를 하지 않으면 리턴
    // if (chb_areaMgntYn.checked == false)
    //     return true;

    if ($c.gus.cfIsNull(ed_zip.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["우편번호"]);
        ed_zip.focus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_siteAddr1.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["주소"]);
        ed_zip.focus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_siteAddr2.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["상세주소"]);
        txt_siteAddr2.focus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_area.getValue()) || parseInt(ed_area.getValue()) <= 0) {
        await $c.gus.cfAlertMsg("면적은 0보다 큰 값이어야 합니다.");
        ed_area.focus();
        return false;
    }

    if ($c.gus.cfIsNull(ed_pyCnt.getValue()) || parseInt(ed_pyCnt.getValue()) <= 0) {
        await $c.gus.cfAlertMsg("평수는 0보다 큰 값이어야 합니다.");
        ed_pyCnt.focus();
        return false;
    }

    if (!await $c.gus.cfValidate([gr_landinfo])) return false;

    if (ds_landinfo.getTotalRow() < 1) {
        await $c.gus.cfAlertMsg("지번_지목 내역을 한 행이상 입력해야 합니다.");
        return false;
    }

    var sumLotArea = 0;
    var sumLotAcqAmt = 0;
    for (let i = 0; i < ds_landinfo.getTotalRow(); i++) {
        lotArea = ds_landinfo.getCellData(i, "lotArea");
        lotAcqAmt = ds_landinfo.getCellData(i, "lotAcqAmt");

        sumLotArea = sumLotArea + lotArea;
        sumLotAcqAmt = sumLotAcqAmt + lotAcqAmt;
    }

    if (sumLotArea != parseInt(ed_area.getValue())) {
        await $c.gus.cfAlertMsg("면적과 지번면적 합계가 틀립니다.");
        ed_area.focus();
        return false;
    }

    if (sumLotAcqAmt != parseInt(ed_acqAmt.getValue())) {
        await $c.gus.cfAlertMsg("취득가액과  지번취득가액 합계가 틀립니다.");
        ed_acqAmt.focus();
        return false;
    }

    return true;
}

//-------------------------------------------------------------------------
// 입력 초기화
//-------------------------------------------------------------------------
scwin.f_Reset = function () {

    // dma_aset.setEmptyValue();				
    ds_asetList.removeAll();              //자산 데이터셋
    ds_landinfo.removeAll();			//지번 데이터셋
    //ds_asetKnd.ClearData();				//자산종류 데이터셋

    //bdLandInfo.ActiveBind = false;

    hid_asetKndNm.setValue("");			//자산종류명 검증용
    hid_asetAcctDeptCd.setValue("");	//자산 귀속부서 검증용

    scwin.f_AsetOnOff(false);				//자산입력 disable
    scwin.f_ClearLandInfo();					//지번지목 초기화
}

//-------------------------------------------------------------------------
// 자산 취소 시 지번지목 취소 처리 (사용x)
//-------------------------------------------------------------------------
scwin.f_CancelLandInfo = function (fixedAsetNo) {
    var rowCnt = 0;		//ds_landinfo 에서 fixedAsetNo row count

    if (fixedAsetNo == "") return;

    //row count를 구한다.
    for (var i = 0; i < ds_landinfo.getTotalRow(); i++) {
        if (ds_landinfo.getCellData(i, "fixedAsetNo") == fixedAsetNo) {
            rowCnt++;
        }
    }
    if (rowCnt == 0) return;

    //데이터셋의 CountRow가 변하므로 row count가 0이면 루프를 빠져나온다.
    while (true) {
        for (var i = 0; i < ds_landinfo.getTotalRow(); i++) {
            if (ds_landinfo.getCellData(i, "fixedAsetNo") == fixedAsetNo) {
                ds_landinfo.Undo(i);
                rowCnt--;
            }
        }
        if (rowCnt == 0) return;
    }
}

//-------------------------------------------------------------------------
// 지번/지목 입력 컨트롤 초기화
//-------------------------------------------------------------------------
scwin.f_ClearLandInfo = function () {
    ed_area.setValue("0");					//면적
    ed_pyCnt.setValue("0");					//평수
    ed_ancdLpr.setValue("0");				//공시지가
    ed_ancdLprStdDt.setValue("");		//공시지가기준일
    ds_landinfo.removeAll()             //지번-지목 데이터 삭제          
}

//-------------------------------------------------------------------------
// 자산내역 조회
//-------------------------------------------------------------------------
scwin.f_SrchAsetContent = function () {
    var row = 0;
    if (!$c.gus.cfIsNull(ds_master.getRowPosition())) {
        row = ds_master.getRowPosition();
    }
    var fixedAsetNo = ds_master.getCellData(row, "fixedAsetNo");
    var assetCoCd = ds_master.getCellData(row, "coCd");
    var assetCoClsCd = ds_master.getCellData(row, "coClsCd");

    if (fixedAsetNo != "") {
        if (assetCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {   // 자회사인 경우에만  회사코드 check
            sbm_aset.action = "/ac.fi.fixedaset.RetrieveAssetsContentsCMD.do"
                + "?fixedAsetNo=" + fixedAsetNo + "&coCd=" + assetCoCd + "&coClsCd=" + assetCoClsCd;
        } else {
            sbm_aset.action = "/ac.fi.fixedaset.RetrieveAssetsContentsCMD.do"
                + "?fixedAsetNo=" + fixedAsetNo;
        }
        $c.sbm.execute(sbm_aset);
    }


    /*
    ds_aset.DataID = "/ac.fi.fixedaset.RetrieveAssetsContentsCMD.do"
                                + "?fixedAsetNo=" + ds_master.NameString(ds_master.RowPosition,"fixedAsetNo");
    ds_aset.Reset();
    */
}

//-------------------------------------------------------------------------
// 고정자산 입력 Enable/Disable
//-------------------------------------------------------------------------
scwin.f_AsetOnOff = function (bEnable) {
    //(bEnable==true) ? cfEnableObjects(tbl_aset) : cfDisableObjects(tbl_aset);
    if (bEnable) {
        $c.gus.cfEnableObjects([ed_fixedAsetNm, ed_zip, ed_siteAddr2
            , chb_tempTaxDeductYn, ed_rmk]);
    } else {
        $c.gus.cfDisableObjects([ed_fixedAsetNm, ed_zip, ed_siteAddr2
            , chb_tempTaxDeductYn, ed_rmk]);
    }
    //txt_svcLife.value = "";
}

//-------------------------------------------------------------------------
// 면적관리자산일 경우에  입력 컨트롤 Enable/Disable
//-------------------------------------------------------------------------
scwin.f_AreaMgntOnOff = function (bEnable) {
    if (bEnable) {
        $c.gus.cfEnableObjects([ed_area, ed_pyCnt, ed_ancdLpr, ed_ancdLprStdDt
            , udc_bottomBtn]);
    } else {
        $c.gus.cfDisableObjects([ed_area, ed_realArea, ed_pyCnt, ed_ancdLpr, ed_ancdLprStdDt
            , udc_bottomBtn]);
    }
}

