//-------------------------------------------------------------------------
// 조회 귀속부서코드 팝업
//-------------------------------------------------------------------------
scwin.f_srchDeptPopUp = function (sIsEvent) {

    var param = '';
    // 자회사 회계 시스템인 경우에는 자회사 소속 귀속부서만 조회   
    if (scwin.isSubCompany) {
        param = "," + scwin.vCoCd + "," + scwin.vCoClsCd;
    }


    udc_retrieveAcctDept.cfCommonPopUp(scwin.udc_retrieveAcctDept_callBack, ed_srchAcctDeptCd.getValue(), ""
        , "T"
        , null, null, null, null
        , param, 410, null, null, null);

}

scwin.udc_retrieveAcctDept_callBack = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {

            ed_srchAcctDeptCd.setValue(rtnList[0]);
            ed_srchAcctDeptCd.options.hidVal = rtnList[0];
            ed_srchAcctDeptNm.setValue(rtnList[1]);

            //회사 정보 set
            scwin.txtCoCd = rtnList[8];		//회사코드 
            scwin.txtCoClsCd = rtnList[9];		//회사구분코드  
        }
    } else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptCd.options.hidVal = "";
        ed_srchAcctDeptNm.setValue("");
    }

    ed_srchAcctDeptNm.focus();
}

//-------------------------------------------------------------------------
// 우편번호팝업
//-------------------------------------------------------------------------
// todo
scwin.f_zipPopUp = function (ed_zip, txt_addr1, txt_addr2) {
    var rtnList = new Array();
    var popupResult = window.showModalDialog("/cm/zz/newzipcodePopup.jsp", "",
        "dialogHeight:400px;dialogWidth:530px;center:yes;scroll:no;status:no;help:no");

    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (popupResult != null) {
        ed_zip.Text = popupResult.zip;
        txt_addr1.value = popupResult.addr1;
        txt_addr2.focus();
    } else {
        ed_zip.Text = "";
        txt_addr1.value = "";
        txt_addr2.value = "";
        ed_zip.focus();
    }
}

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel = async function () {

    if (ds_master.getTotalRow() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  //"조회결과가 존재하지 않습니다."
        return;
    } else {
        if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {

            var options = {
                fileName: "고정자산조회.xlsx",
                sheetName: "고정자산조회",
            };

            $c.data.downloadGridViewExcel(gr_master, options);
        }
    }
}

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_Excel2 = async function () {

    if (ds_landinfo.getTotalRow() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  //"조회결과가 존재하지 않습니다."
        return;
    } else {
        if (await $c.win.confirm("Excel로 다운로드 하시겠습니까?")) {
            var options = {
                fileName: "지번지목리스트.xlsx",
                sheetName: "지번지목리스트",
                hiddenVisible: true
            };

            $c.data.downloadGridViewExcel(gr_landinfo, options);
        }
    }

}

scwin.udc_retrieveAcctDept_onclickEvent = function (e) {
    scwin.f_srchDeptPopUp();
};

scwin.udc_retrieveAcctDept_onblurCodeEvent = function (e) {

    if ($c.gus.cfIsNull(ed_srchAcctDeptCd.getValue())) {
        ed_srchAcctDeptNm.setValue("");
        scwin.hid_srchAcctDeptCd = "";
        return;
    }

    if (ed_srchAcctDeptCd.getValue().trim() == scwin.hid_srchAcctDeptCd) return;

    scwin.f_srchDeptPopUp();
};

scwin.udc_zip_onclickEvent = function (e) {
    scwin.f_zipPopUp(ed_zip, ed_siteAddr1, ed_siteAddr2)
};

scwin.sbm_search_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        var rowCnt = ds_master.getTotalRow();
        ed_totalRow1.setValue(rowCnt);

        if (rowCnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            // dma_aset.setEmptyValue();
            ds_asetList.removeAll()
            ds_landinfo.removeAll();
            // cfDisableBtn([bUpdate,bSave]);
        } else {
            scwin.f_AsetOnOff(false);
            scwin.f_AreaMgntOnOff(false);
            // cfDisableBtn([bSave]);

            // scwin.f_SrchAsetKnd('');

            scwin.f_SrchAsetContent();

            for (let i = 0; i < ds_master.getTotalRow(); i++) {
                ds_master.setCellData(i, "fixedAsetNm2", ds_master.getCellData(i, "fixedAsetNm"));
            }


        }

        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        }

    }
};

scwin.ds_master_onrowpositionchange = function (info) {
    // if(cfCheckCreateFlag() == true) return;
    scwin.f_SrchAsetContent();
};

scwin.gr_master_oncellclick = function (rowIndex, columnIndex, columnId) {
    // if (cfCheckCreateFlag() == true) return;
    scwin.f_SrchAsetContent();
};

scwin.ed_srchOrgFixedAsetNo_onblur = function (e) {
    if (ed_srchOrgFixedAsetNo.getValue().trim() == "") return;
    ed_srchOrgFixedAsetNo.setValue($c.gus.cfGetLeftPad(ed_srchOrgFixedAsetNo.getValue(), 10))
};

scwin.ed_srchFixedAsetNo_onblur = function (e) {

    if (ed_srchFixedAsetNo.getValue().trim() == "") return;
    ed_srchFixedAsetNo.setValue($c.gus.cfGetLeftPad(ed_srchFixedAsetNo.getValue(), 10));
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

scwin.sbm_aset_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if (ds_asetList.getTotalRow() > 0) {
            ds_asetList.setRowPosition(0);
            // dma_aset.setJSON(ds_asetList.getRowJSON(0));
            acb_srchAsetPatternCd.setValue(acb_asetPatternCd.getValue());
        }

        ed_totalRow2.setValue(ds_landinfo.getTotalRow());
    }
};

scwin.zipCostomFormat = function (value, formattedValue, rowIndex, colIndex) {
    var zip = ds_master.getCellData(rowIndex, "zip");
    var siteAddr1 = ds_master.getCellData(rowIndex, "siteAddr1");
    var siteAddr2 = ds_master.getCellData(rowIndex, "siteAddr2");

    return zip + " " + siteAddr1 + " " + siteAddr2;
}

scwin.gridFormat = function (value) {
    if (value == "1") {
        return "Y";
    } else if (value == "0") {
        return "N";
    }
}
